import requests
from urllib.parse import urlparse

def is_valid_url(url):
    try:
        result = urlparse(url)
        return all([result.scheme, result.netloc])
    except ValueError:
        return False

def is_allowed_destination(url):
    allowed_domains = ['example.com', 'anotherexample.com']  # Add allowed domains here
    parsed_url = urlparse(url)
    return parsed_url.hostname in allowed_domains

def is_safe_ip(ip):
    private_ip_ranges = [
        ('10.0.0.0', '10.255.255.255'),
        ('172.16.0.0', '172.31.255.255'),
        ('192.168.0.0', '192.168.255.255'),
        ('127.0.0.0', '127.255.255.255')
    ]
    ip_parts = list(map(int, ip.split('.')))
    for start, end in private_ip_ranges:
        start_parts = list(map(int, start.split('.')))
        end_parts = list(map(int, end.split('.')))
        if start_parts <= ip_parts <= end_parts:
            return False
    return True

def fetch_url_content(url):
    if not is_valid_url(url):
        raise ValueError("Invalid URL")
    
    if not is_allowed_destination(url):
        raise ValueError("Destination not allowed")
    
    try:
        response = requests.get(url, allow_redirects=False)
        if response.is_redirect:
            raise ValueError("Redirects are not allowed")
        
        ip = response.raw._connection.sock.getpeername()[0]
        if not is_safe_ip(ip):
            raise ValueError("Unsafe IP address")
        
        return response.text
    except requests.RequestException as e:
        raise RuntimeError(f"Failed to fetch URL content: {e}")

